sql:
SELECT service_id, date, total_bookings, average_rating
FROM service_performance
ORDER BY date DESC;

SELECT service_name 
FROM services 
ORDER BY store_id, service_id;

external_knowledge:
- "Last month" refers to the period from the first day of the previous month to the last day of the previous month.; 
- "Top 3 services" refers to the services with the highest total revenue.; 
- "Revenue" refers to the amount of money earned from the services.
